'use client'

import { useState, useEffect, useRef } from 'react'
import { useRouter } from 'next/navigation'
import { useAuth } from '@/contexts/AuthContext'
import { supabase } from '@/lib/supabase'
import { Send, Clock } from 'lucide-react'
import SuggestedQuestions from '@/components/SuggestedQuestions'
import { query } from '@/lib/chat'
import ReactMarkdown from 'react-markdown'

interface Message {
  id: string
  role: 'user' | 'assistant'
  content: string
  created_at: string
}

export default function ChatPage() {
  const { user, loading: authLoading, signOut } = useAuth()
  const router = useRouter()
  const [messages, setMessages] = useState<Message[]>([])
  const [input, setInput] = useState('')
  const [loading, setLoading] = useState(false)
  const [showQuestions, setShowQuestions] = useState(false)
  const messagesEndRef = useRef<HTMLDivElement>(null)

  useEffect(() => {
    if (!authLoading && !user) {
      router.push('/auth')
    }
  }, [user, authLoading, router])

  useEffect(() => {
    if (user) {
      loadMessages()
      // Add initial welcome message if no messages exist
      setTimeout(() => {
        setMessages(prev => {
          if (prev.length === 0) {
            const welcomeMessage: Message = {
              id: Date.now().toString(),
              role: 'assistant',
              content: 'Merhaba! Ben Baykuş AI. YKS hazırlık sürecinde size yardımcı olmak için buradayım. Matematik, Türkçe, Fizik, Kimya, Biyoloji, Tarih, Coğrafya ve Felsefe derslerinde sorularınızı yanıtlayabilirim. Hangi konuda destek almak istersiniz?',
              created_at: new Date().toISOString(),
            }
            return [welcomeMessage]
          }
          return prev
        })
      }, 500)
    }
  }, [user])

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' })
  }, [messages])

  const loadMessages = async () => {
    // Messages table doesn't exist yet, skipping load
    // TODO: Create messages table in Supabase
  }

  const handleSend = async (question?: string) => {
    const messageText = question || input
    if (!messageText.trim() || !user) return

    setLoading(true)
    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: messageText,
      created_at: new Date().toISOString(),
    }

    setMessages((prev) => [...prev, userMessage])
    setInput('')

    // Save user message to Supabase
    // TODO: Create messages table in Supabase
    // await supabase.from('messages').insert({
    //   user_id: user.id,
    //   role: 'user',
    //   content: messageText,
    // })

    // Get real AI response
    try {
      const response = await query({ question: messageText })
      console.log('API Response:', response)
      
      let answerText = ''
      
      // Check different possible response structures
      if (response && typeof response === 'object') {
        answerText = response.answer || response.response || response.text || response.message || JSON.stringify(response)
      } else if (typeof response === 'string') {
        answerText = response
      } else {
        answerText = 'Üzgünüm, bir hata oldu. Lütfen tekrar deneyin.'
      }
      
      const assistantMessage: Message = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        content: answerText,
        created_at: new Date().toISOString(),
      }

      setMessages((prev) => [...prev, assistantMessage])

      // Save assistant message to Supabase
      // TODO: Create messages table in Supabase
      // await supabase.from('messages').insert({
      //   user_id: user.id,
      //   role: 'assistant',
      //   content: assistantMessage.content,
      // })
    } catch (error) {
      console.error('Chat API error:', error)
      const errorMessage: Message = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        content: 'Üzgünüm, bir hata oldu. Lütfen tekrar deneyin.',
        created_at: new Date().toISOString(),
      }
      setMessages((prev) => [...prev, errorMessage])
    }

    setLoading(false)
  }

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault()
      handleSend()
    }
  }

  if (authLoading || !user) {
    return null
  }

  return (
    <div className="h-screen flex flex-col bg-white overflow-hidden">
      {/* Fixed Header Logo */}
      <div className="flex-none flex justify-center pt-4 pb-2 bg-white">
        <img src="/baykus.png" alt="Baykuş" width="50" height="38" />
      </div>

      {/* Main Chat Area - Scrollable */}
      <div className="flex-1 overflow-y-auto px-4 py-4 min-h-0">
        <div className="max-w-xl mx-auto">
          {messages.length === 0 ? (
            <div className="flex items-center justify-center h-full">
            </div>
          ) : (
            // Messages with background logo
            <div className="relative space-y-4 min-h-full">
              {/* Background watermark - always visible */}
              <div className="fixed inset-0 opacity-5 pointer-events-none flex items-center justify-center z-0">
                <img src="/baykus.png" alt="" width="200" height="153" />
              </div>
              
              <div className="relative z-10 space-y-4">
                {messages.map((message) => (
                  <div key={message.id} className={`flex ${message.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                    {message.role === 'assistant' ? (
                      <div className="flex flex-col items-start max-w-[85%]">
                        <img src="/baykus.png" alt="" width="24" height="18" className="mb-1" />
                        <div className="py-1 text-black">
                          <p className="text-xs leading-relaxed">{message.content}</p>
                        </div>
                      </div>
                    ) : (
                      <div className="max-w-[85%] px-3 py-2 bg-[#0c003d] text-white rounded-2xl rounded-tr-sm">
                        <p className="text-xs">{message.content}</p>
                      </div>
                    )}
                  </div>
                ))}
              {loading && (
                <div className="flex justify-start">
                  <div className="flex flex-col items-start max-w-[85%]">
                    <img src="/baykus.png" alt="" width="24" height="18" className="mb-1" />
                    <div className="py-1 text-[#0c003d] text-xs">Yazıyor...</div>
                  </div>
                </div>
              )}
              <div ref={messagesEndRef} />
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Fixed Input Area */}
      <div className="flex-none px-4 pb-2 pt-2 bg-white border-t border-gray-100">
        <div className="max-w-xl mx-auto">
          <div className="flex items-center border-2 border-[#0c003d] rounded-full px-3 py-2 bg-white shadow-sm">
            <button
              onClick={() => setShowQuestions(!showQuestions)}
              className="text-[#0c003d] mr-2 flex-shrink-0 hover:scale-110 transition-transform"
              title="Örnek sorular"
            >
              <Clock size={16} />
            </button>
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyPress={handleKeyPress}
              placeholder="Bana soru sor"
              className="flex-1 bg-transparent outline-none text-sm text-[#0c003d] placeholder-gray-400 min-w-0"
              disabled={loading}
            />
            <button
              onClick={() => handleSend()}
              disabled={loading || !input.trim()}
              className="ml-2 text-[#0c003d] disabled:opacity-50 flex-shrink-0"
            >
              <Send size={16} />
            </button>
          </div>
          <p className="text-center text-[10px] text-gray-400 mt-1 mb-1">
            Demo amaçlı yapılmıştır. Veriler profesyonel koç verisi değildir!
          </p>
        </div>
      </div>

      {/* Balloon Popup */}
      {showQuestions && (
        <div className="fixed bottom-20 z-50" style={{ left: '1rem' }}>
          <div className="bg-white rounded-xl border border-[#0c003d] shadow-lg max-w-xs">
            
            <div className="p-3">
              <div className="flex justify-between items-center mb-2">
                <h3 className="text-xs font-bold text-[#0c003d]">Örnek Sorular</h3>
                <button
                  onClick={() => setShowQuestions(false)}
                  className="text-gray-400 hover:text-gray-600 ml-2"
                >
                  <svg width="12" height="12" viewBox="0 0 12 12" fill="currentColor">
                    <path fillRule="evenodd" d="M3.268 3.268a.5.5 0 01.707 0L6 5.293l2.025-2.025a.5.5 0 01.708.708L6.707 6l2.025 2.025a.5.5 0 01-.708.708L6 6.707 3.975 8.732a.5.5 0 01-.708-.708L5.293 6 3.268 3.975a.5.5 0 010-.708z" clipRule="evenodd" />
                  </svg>
                </button>
              </div>
              <div className="max-h-40 overflow-y-auto">
                <SuggestedQuestions onQuestionClick={(question) => {
                  handleSend(question)
                  setShowQuestions(false)
                }} />
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}
